#include<bits/stdc++.h>
using namespace std;
long long n,dp[100000+5],k,tot,ans;
void ass()
{
	for(int i=2;i<=70000/i;i++)
	{
		if(dp[i]==0)
		{
			for(int j=2;j<=70000/i;j++)
			{
				dp[i*j]=1;
			}
		}
	}
}
int main()
{
	cin>>n;
	if(n==0 or n==1)
	{
		cout<<0;
		return 0;
	}
	dp[1]=1;
	ass();
	ans=n;
	while(ans-dp[k]>=0)
	{
//		cout<<dp[k]<<" "<<k<<" ";
		if(dp[k]==0 and ans-k>=0 and k!=0)
		{
			cout<<k<<"\n";
			tot++;
			ans-=k;
		}
//		cout<<ans<<"\n";
		k++;
	}
	cout<<tot;
	return 0;
}
